
"use client";

import React, { useState } from 'react';
import { getUsers, saveUsers, setCurrentUser, addAdminNotification } from '@/lib/store';
import { User, Role } from '@/lib/types';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { 
  Lock,
  Mail,
  Eye,
  EyeOff,
  Mountain
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { toast } from '@/hooks/use-toast';

interface AuthScreenProps {
  onLogin: (user: User) => void;
}

type AuthMode = 'login' | 'signup';

export default function AuthScreen({ onLogin }: AuthScreenProps) {
  const [mode, setMode] = useState<AuthMode>('login');
  const [error, setError] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  // Form Fields
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const users = getUsers();
    const user = users[email.toLowerCase()];

    if (!user || user.password !== password) {
      setError('Invalid identity credentials.');
      return;
    }

    if (user.role === 'organizer') {
      if (user.isRejected) {
        setError(`Registry Rejected: ${user.rejectionReason || 'Compliance audit failure.'}`);
        return;
      }
      if (!user.isApproved) {
        setError('Organizer registry pending audit. Please check back later.');
        return;
      }
    }

    if (user.status === 'suspended' || user.status === 'blocked') {
      setError(`Account ${user.status}. Contact administration.`);
      return;
    }

    setCurrentUser(user);
    onLogin(user);
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!email || !password) {
      setError('Email and password are required.');
      return;
    }

    const users = getUsers();
    if (users[email.toLowerCase()]) {
      setError('Identity already registered.');
      return;
    }

    const newUser: User = {
      email: email.toLowerCase(),
      password,
      firstName: email.split('@')[0],
      role: 'user',
      createdAt: new Date().toISOString(),
      isApproved: true,
      isRejected: false,
      status: 'active',
    };

    users[email.toLowerCase()] = newUser;
    saveUsers(users);

    toast({ title: 'Account Created', description: 'Your account has been successfully created. Please login.' });
    setMode('login');
  };

  const handleGoogleSignIn = () => {
    const googleEmail = "trailwise.adventurer@gmail.com";
    const users = getUsers();
    let user = users[googleEmail];

    if (!user) {
        const newUser: User = {
            email: googleEmail,
            firstName: "TrailWise",
            lastName: "Adventurer",
            password: "google-signed-in",
            role: 'user',
            createdAt: new Date().toISOString(),
            isApproved: true,
            isRejected: false,
            status: 'active',
        };
        users[googleEmail] = newUser;
        saveUsers(users);
        user = newUser;
        
        toast({
            title: "Welcome Adventurer!",
            description: "Your new account has been created via Google.",
        });
    }

    setCurrentUser(user);
    onLogin(user);
  };


  const GoogleIcon = () => (
    <svg className="w-5 h-5" viewBox="0 0 48 48">
      <path fill="#FFC107" d="M43.611 20.083H42V20H24v8h11.303c-1.649 4.657-6.08 8-11.303 8c-6.627 0-12-5.373-12-12s5.373-12 12-12c3.059 0 5.842 1.154 7.961 3.039l5.657-5.657C34.046 6.053 29.268 4 24 4C12.955 4 4 12.955 4 24s8.955 20 20 20s20-8.955 20-20c0-1.341-.138-2.65-.389-3.917z"></path>
      <path fill="#FF3D00" d="M6.306 14.691l6.571 4.819C14.655 15.108 18.961 12 24 12c3.059 0 5.842 1.154 7.961 3.039l5.657-5.657C34.046 6.053 29.268 4 24 4C16.318 4 9.656 8.337 6.306 14.691z"></path>
      <path fill="#4CAF50" d="M24 44c5.166 0 9.86-1.977 13.409-5.192l-6.19-5.238A11.91 11.91 0 0 1 24 36c-5.222 0-9.612-3.87-11.283-8.951l-6.522 5.025C9.505 39.556 16.227 44 24 44z"></path>
      <path fill="#1976D2" d="M43.611 20.083H42V20H24v8h11.303c-.792 2.237-2.231 4.166-4.087 5.571l6.19 5.238C43.021 36.251 46 30.694 46 24c0-1.341-.138-2.65-.389-3.917z"></path>
    </svg>
  );

  return (
    <div className="min-h-screen w-full flex font-sans">
      {/* Left Column */}
      <div className="w-full md:w-1/2 min-h-screen relative flex items-center justify-center p-6 sm:p-8 md:p-12 bg-cover bg-center" style={{ backgroundImage: "url('https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?q=80&w=2070&auto=format&fit=crop')"}}>
        <div className="absolute inset-0 bg-black/50 backdrop-blur-sm z-0" />
        <div className="relative z-10 w-full max-w-md bg-white/10 backdrop-blur-xl rounded-2xl shadow-2xl border border-white/20 p-6 sm:p-8 text-white animate-in fade-in zoom-in duration-700">
          
          {/* Header */}
          <div className="text-center mb-8">
            <div className="flex justify-center items-center gap-2 mb-2">
              <Mountain className="w-8 h-8 text-white" />
              <h1 className="text-2xl font-bold tracking-tight">Adventure Camp</h1>
            </div>
            <p className="text-xs uppercase font-semibold tracking-widest text-white/70">
              CAMP ORGANISER PLATFORM
            </p>
            <h2 className="text-3xl font-light mt-6">Welcome 👋</h2>
          </div>

          {/* Tabs */}
          <div className="mb-8">
            <div className="flex bg-black/20 rounded-lg p-1">
              <button
                onClick={() => setMode('login')}
                className={cn(
                  "w-full py-2.5 rounded text-sm font-bold uppercase tracking-wider transition-colors duration-300",
                  mode === 'login' ? 'bg-maroon-600 text-white shadow-lg' : 'text-white/60 hover:bg-white/10'
                )}
              >
                Login
              </button>
              <button
                onClick={() => setMode('signup')}
                className={cn(
                  "w-full py-2.5 rounded text-sm font-bold uppercase tracking-wider transition-colors duration-300",
                  mode === 'signup' ? 'bg-maroon-600 text-white shadow-lg' : 'text-white/60 hover:bg-white/10'
                )}
              >
                Sign Up
              </button>
            </div>
          </div>

          {error && <Alert variant="destructive" className="rounded-lg border-none bg-red-900/80 text-white mb-6 text-center"><AlertDescription className="text-xs font-medium">{error}</AlertDescription></Alert>}

          {/* Form */}
          <form onSubmit={mode === 'login' ? handleLogin : handleSignup} className="space-y-6">
            <div className="space-y-2">
              <Label className="text-xs font-bold uppercase text-white/80">EMAIL</Label>
              <div className="relative group">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/40 group-focus-within:text-white" />
                <Input 
                  type="email" 
                  value={email} 
                  onChange={e => setEmail(e.target.value)} 
                  className="h-12 rounded-lg border-white/20 bg-white/10 font-medium text-white placeholder:text-white/50 pl-10" 
                  placeholder="admin@gmail.com"
                  required 
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label className="text-xs font-bold uppercase text-white/80">PASSWORD</Label>
              <div className="relative group">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/40 group-focus-within:text-white" />
                <Input 
                  type={showPassword ? 'text' : 'password'} 
                  value={password} 
                  onChange={e => setPassword(e.target.value)} 
                  className="h-12 rounded-lg border-white/20 bg-white/10 font-medium text-white placeholder:text-white/50 pl-10 pr-10" 
                  placeholder="••••••••"
                  required 
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-white/40 hover:text-white">
                  {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
              <div className="text-right">
                <a href="#" className="text-xs text-maroon-300 hover:underline">Forgot password?</a>
              </div>
            </div>

            <Button type="submit" className="w-full h-12 bg-green-600 hover:bg-green-700 text-white font-bold text-sm uppercase tracking-wider rounded-lg shadow-md transition-all">
              {mode === 'login' ? 'Login' : 'Sign Up'}
            </Button>
          </form>
          
          {/* Social Login */}
          <div className="mt-8">
            <div className="relative">
              <div className="absolute inset-0 flex items-center">
                <span className="w-full border-t border-white/20" />
              </div>
              <div className="relative flex justify-center text-xs">
                <span className="bg-white/10 px-2 text-white/80 backdrop-blur-sm">or Sign in with Google</span>
              </div>
            </div>
            <Button variant="outline" className="w-full mt-4 h-12 bg-white text-gray-800 hover:bg-gray-200 font-semibold rounded-lg shadow-sm flex items-center justify-center gap-2" onClick={handleGoogleSignIn}>
              <GoogleIcon />
              Continue with Google
            </Button>
          </div>
        </div>
      </div>

      {/* Right Column */}
      <div className="hidden md:flex md:w-1/2 min-h-screen bg-cream-50 items-center justify-center p-12">
        <div className="max-w-md">
            <img src="https://i.ibb.co/6g3h153/image-3.png" alt="Female camper with a deer in a forest" className="w-full h-auto object-contain rounded-lg" />
        </div>
      </div>
    </div>
  );
}
